Here's a well-structured MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, HttpClient client) CreateFetcher(HttpMessageHandler handler)
    {
        var client = new HttpClient(handler);
        return (new DataFetcher(client), client);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(() =>
        {
            cts.Cancel(); // simulate cancel during request
            cts.Token.ThrowIfCancellationRequested();
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutExpires_IsCancelledViaTestContext()
    {
        // Arrange — handler delays longer than [Timeout]
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var (fetcher, client) = CreateFetcher(handler);
        using var _ = client;

        // Act & Assert — TestContext.CancellationToken fires when timeout elapses
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    // Minimal fake handler to avoid external mocking dependencies
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => Task.FromResult(response)) { }

        public FakeHandler(Func<HttpResponseMessage> syncFactory)
            : this(_ => Task.FromResult(syncFactory())) { }

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> asyncFactory)
        {
            _factory = asyncFactory;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| `Assert.ThrowsExactlyAsync` | Verifies exact exception type with clear failure messages |
| `Assert.ThrowsAsync` | Matches `OperationCanceledException` *or* derived `TaskCanceledException` |
| `FakeHandler` | Controls `HttpClient` behavior without external mocking libraries |
| Sealed test class | Performance and design clarity |

The critical insight for cancellation testing: always pass `TestContext.CancellationToken` (or your own `CancellationTokenSource.Token`) into the method under test — never `CancellationToken.None`. This lets `[Timeout]` actually halt a stuck test instead of waiting forever.
